import './Main.css'
import POST from '../Post/Post'
import React, { Component } from 'react'

export default class Main extends Component {
    render() {
        const { list, tag, listVisible } = this.props
        let array = []
        user
        function params(index, i) {
            return list[`num${i}`].tags.indexOf(tag.split(",")[index]) !== -1
        }
        if (this.props.userPosts) {//                                                    Account
            for (let i = 0; i < Object.keys(list).length; i++) {
                array.push(<POST key={this.props.list[`num${i}`].id} x={true} list={this.props.list[`num${i}`]} />)
            }
        } else if (this.props.userLikes) {

        }else if (listVisible.length === 0) {//                                        liatVisible === 0 - MAIN 
            for (let i = 0; i < Object.keys(list).length; i++) {
                array.push(<POST key={list[`num${i}`].id} userLikes={this.props.userLikes} x_l={true} list={list[`num${i}`]} />)
            }
        } else if (tag !== null) {//                                                     POSTWINDOWS
            for (let i = 0; i < Object.keys(list).length; i++) {
                if ((params(0, i) || params(1, i) || params(2, i) || params(3, i)) && this.props.list[`num${i}`].id !== this.props.idPost) {
                    array.push(
                        <POST key={this.props.list[`num${i}`].id} list={this.props.list[`num${i}`]} />
                    )
                }
            }
        } else {//                                                                       listVisible !== 0 - MAIN 
            for (let i = 0; i < Object.keys(list).length; i++) {
                if (list[`num${i}`].tags.indexOf(listVisible.toLowerCase()) !== -1) {
                    array.push(<POST key={list[`num${i}`].id} list={list[`num${i}`]} />)
                }
            }
        }

        return (
            <div className="main-block">
                {array}
            </div>
        )
    }
}
